// Generates a small batch of synthetic Atlas transactions to feed the demo.
const categories = ['office_supplies','software_saas','travel','meals','utilities','consulting','marketing','equipment','shipping','fuel'];
const vendorIds = Array.from({length: 25}, (_, i) => i + 1);
const customerIds = Array.from({length: 50}, (_, i) => i + 1);
const count = Math.floor(Math.random() * 11) + 5; // 5-15
const today = new Date().toISOString().slice(0,10);
const out = [];
for (let i = 0; i < count; i++) {
  const amount = Math.round((Math.random() * 4900 + 50) * 100) / 100;
  const category = categories[Math.floor(Math.random() * categories.length)];
  const vendor_id = vendorIds[Math.floor(Math.random() * vendorIds.length)];
  const customer_id = customerIds[Math.floor(Math.random() * customerIds.length)];
  out.push({
    json: {
      amount,
      category,
      vendor_id,
      customer_id,
      description: `${category.replace('_',' ')} - batch ingest ${today}`,
      flagged: false
    }
  });
}
return out;
